-- 4. Insert etichete; duplicate ignorate (DUP_VAL_ON_INDEX) IF p_etichete_ids.COUNT > 0 THEN FOR i IN 1 .. p_etichete_ids.COUNT LOOP BEGIN INSERT INTO recenzii_etichete(id_recenzie, id_eticheta) VALUES (p_id_recenzie, p_etichete_ids(i)); EXCEPTION WHEN DUP_VAL_ON_INDEX THEN NULL; END; END LOOP; END IF;
-- 5. Insert comentarii per actor; trg_validare_actor_recenzie (-20001) -- valideaza ca actorul apartine distributiei filmului IF p_actori_ids.COUNT > 0 THEN FOR i IN 1 .. p_actori_ids.COUNT LOOP IF p_actori_comentarii(i) IS NOT NULL AND LENGTH(TRIM(p_actori_comentarii(i))) > 0 THEN INSERT INTO recenzii_actori(id_recenzie, id_actor, comentariu) VALUES (p_id_recenzie, p_actori_ids(i), p_actori_comentarii(i)); END IF; END LOOP; END IF;
EXCEPTION WHEN e_input_invalid THEN RAISE_APPLICATION_ERROR(-20100, 'Date invalide: nota trebuie 1-10 si comentariul nu poate fi gol'); WHEN e_arrays_nepotrivite THEN RAISE_APPLICATION_ERROR(-20101, 'Numarul de id-uri actori nu corespunde cu numarul de comentarii'); WHEN e_client_inexistent THEN RAISE_APPLICATION_ERROR(-20102, 'Clientul cu id ' || p_id_client || ' nu exista'); WHEN e_film_inexistent THEN RAISE_APPLICATION_ERROR(-20103, 'Filmul cu id ' || p_id_film || ' nu exista'); WHEN DUP_VAL_ON_INDEX THEN IF SQLERRM LIKE '%UQ_RECENZIE_CLIENT_FILM%' THEN RAISE_APPLICATION_ERROR(-20104, 'Exista deja o recenzie de la acest client pentru acest film'); ELSE RAISE; END IF; WHEN OTHERS THEN ROLLBACK TO sp_recenzie; RAISE; END p_creeaza_recenzie_completa; / -- PRINT rc;

const API = '';

async function request(path, options = {}) {
  const res = await fetch(`${API}${path}`, {
    headers: { 'Content-Type': 'application/json' },
    ...options
  });

  if (!res.ok) {
    const text = await res.text();
    let message = `HTTP ${res.status}`;
    try {
      const parsed = text ? JSON.parse(text) : null;
      message = parsed?.error || parsed?.message || message;
    } catch {
      if (text) message = text;
    }
    const err = new Error(message);
    err.status = res.status;
    throw err;
  }

  if (res.status === 204) return null;
  const bodyText = await res.text();
  if (!bodyText) return null;
  return JSON.parse(bodyText);
}

export const api = {
  login: (username, parola) =>
    request('/api/auth/login', {
      method: 'POST',
      body: JSON.stringify({ username, parola })
    }),
  getFilme: () => request('/api/filme'),
  getFilmeByCategorie: (idCategorie) => request(`/api/filme/categorie/${idCategorie}`),
  getFilm: (id) => request(`/api/filme/${id}`),
  getCategorii: () => request('/api/categorii'),
  getVersiuniFilm: (idFilm) => request(`/api/versiuni-film/film/${idFilm}`),
  getRecenziiFilm: (idFilm) => request(`/api/recenzii/film/${idFilm}`),
  postRecenzie: (data) =>
    request('/api/recenzii', { method: 'POST', body: JSON.stringify(data) }),
  updateRecenzie: (id, data) =>
    request(`/api/recenzii/${id}`, { method: 'PUT', body: JSON.stringify(data) }),
  getEtichete: () => request('/api/etichete'),
  addEticheta: (idRecenzie, idEticheta) =>
    request(`/api/recenzii-etichete/${idRecenzie}/${idEticheta}`, { method: 'POST' }),
  postVizualizare: (data) =>
