package com.example.Project.service;

import com.example.Project.dao.AuthDao;
import com.example.Project.dto.response.LoginResponse;
import com.example.Project.model.client.Client;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.stereotype.Service;

@Service
public class AuthService {

    @Autowired
    private AuthDao authDao;

    public LoginResponse login(String username, String parola) {
        if (username == null || username.isBlank())
            throw new IllegalArgumentException("Username-ul este obligatoriu");
        if (parola == null || parola.isBlank())
            throw new IllegalArgumentException("Parola este obligatorie");

        Client client = authDao.findByUsernameAndPassword(username, parola)
                .orElseThrow(() -> new IllegalArgumentException("Username sau parola incorecte"));

        return new LoginResponse(client.getId(), client.getUsername(),
                client.getNume(), client.getPrenume(), client.getEmail());
    }
}

package com.example.Project.service;

import com.example.Project.dao.AuthDao;
import com.example.Project.dto.response.LoginResponse;
import com.example.Project.model.client.Client;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.stereotype.Service;

@Service
public class AuthService {

    @Autowired
    private AuthDao authDao;

    public LoginResponse login(String username, String parola) {
        if (username == null || username.isBlank())
            throw new IllegalArgumentException("Username-ul este obligatoriu");
        if (parola == null || parola.isBlank())
            throw new IllegalArgumentException("Parola este obligatorie");

        Client client = authDao.findByUsernameAndPassword(username, parola)
                .orElseThrow(() -> new IllegalArgumentException("Username sau parola incorecte"));

        return new LoginResponse(client.getId(), client.getUsername(),
                client.getNume(), client.getPrenume(), client.getEmail());
    }

    public LoginResponse register(String username, String parola, String nume, String prenume, String email) {
        if (username == null || username.isBlank())
            throw new IllegalArgumentException("Username-ul este obligatoriu");
        if (parola == null || parola.isBlank())
            throw new IllegalArgumentException("Parola este obligatorie");
        if (nume == null || nume.isBlank())
            throw new IllegalArgumentException("Numele este obligatoriu");
        if (prenume == null || prenume.isBlank())
            throw new IllegalArgumentException("Prenumele este obligatoriu");

        if (authDao.findByUsername(username).isPresent()) {
            throw new IllegalArgumentException("Username deja folosit");
        }

        Long id = authDao.insertBasicClient(nume, prenume, (email == null || email.isBlank()) ? null : email,
                username, parola);

        return new LoginResponse(id, username, nume, prenume, email);
    }
}

package com.example.Project.service;

import com.example.Project.dao.AuthDao;
import com.example.Project.dto.response.ClientResponse;
import com.example.Project.exception.NotFoundException;
import com.example.Project.model.client.Client;
import com.example.Project.model.client.PhoneNumber;
import org.springframework.stereotype.Service;

@Service
public class ClientiService {

    private final AuthDao authDao;

    public ClientiService(AuthDao authDao) {
        this.authDao = authDao;
    }

    public ClientResponse getMe(String username) {
        Client c = authDao.findByUsername(username)
                .orElseThrow(() -> new NotFoundException("Client negasit: " + username));
        return toResponse(c);
    }

    private ClientResponse toResponse(Client c) {
        return new ClientResponse(
                c.getId(),
                c.getUsername(),
                c.getNume(),
                c.getPrenume(),
                c.getEmail(),
                formatPhone(c.getHomePhone()),
                formatPhone(c.getCellphone()),
                c.getAddress(),
                c.getCity(),
                c.getDataNastere()
        );
    }

    private String formatPhone(PhoneNumber phone) {
        if (phone == null) return null;
        return phone.getCode().getPrefix() + " " + phone.getNumber();
    }
}

package com.example.Project.service;

import com.example.Project.dao.AuthDao;
import com.example.Project.dao.ClientiDao;
import com.example.Project.dto.request.UpdateClientRequest;
import com.example.Project.dto.response.ClientResponse;
import com.example.Project.exception.NotFoundException;
import com.example.Project.model.client.Client;
import com.example.Project.model.client.PhoneNumber;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

@Service
public class ClientiService {

    private final AuthDao authDao;
    private final ClientiDao clientiDao;

    public ClientiService(AuthDao authDao, ClientiDao clientiDao) {
        this.authDao = authDao;
        this.clientiDao = clientiDao;
    }

    public ClientResponse getMe(String username) {
        Client c = authDao.findByUsername(username)
                .orElseThrow(() -> new NotFoundException("Client negasit: " + username));
        return toResponse(c);
    }

    @Transactional
    public ClientResponse updateMe(String username, UpdateClientRequest req) {
        Client c = authDao.findByUsername(username)
                .orElseThrow(() -> new NotFoundException("Client negasit: " + username));
        clientiDao.update(c.getId(), req);
        return getMe(username);
    }

    private ClientResponse toResponse(Client c) {
        PhoneNumber homePhone = c.getHomePhone();
        PhoneNumber cellPhone = c.getCellphone();
        String homeCode = homePhone != null ? homePhone.getCode().getPrefix() : null;
        String homeNr = homePhone != null ? homePhone.getNumber() : null;
        String cellCode = cellPhone != null ? cellPhone.getCode().getPrefix() : null;
        String cellNr = cellPhone != null ? cellPhone.getNumber() : null;

        return new ClientResponse(
                c.getId(),
                c.getUsername(),
                c.getNume(),
                c.getPrenume(),
                c.getEmail(),
                homeCode,
                homeNr,
                cellCode,
                cellNr,
                formatPhone(homePhone),
                formatPhone(cellPhone),
                c.getAddress(),
                c.getCity(),
                c.getDataNastere()
        );
    }

    private String formatPhone(PhoneNumber phone) {
        if (phone == null) return null;
        return phone.getCode().getPrefix() + " " + phone.getNumber();
    }
}
